      <!-- Tariff price Pw+t (y=270) solid red -->
      <line x1="65" y1="270" x2="650" y2="270" stroke="#DC2626" stroke-width="1.5"/>

      <!-- Axes -->
      <line x1="65" y1="420" x2="650" y2="420" stroke="#334155" stroke-width="2"/>
