            <!-- Old eq E₀ at AD × SRAS₀ ≈ (144, 131). New eq E₁ at AD × SRAS₁ ≈ (171, 148) -->
            <line x1="144" y1="131" x2="144" y2="220" stroke="#94A3B8" stroke-width="1" stroke-dasharray="3 3"/>
